%% 1. 准则层判断矩阵(一级指标相对于总体目标)
A_B = [1, 5, 3, 7, 1/3;
1/5, 1, 1/3, 3, 1/5;
1/3, 3, 1, 5, 1/3;
1/7, 1/3, 1/5, 1, 1/7;
3, 5, 3, 7, 1]; % 示例判断矩阵，请根据实际情况填写
[W_B, CR_B] = AHP_calculate_weight(A_B, '准则层');
disp('准则层权重(W_B):');
disp(W_B);
fprintf('准则层一致性比率CR_B: %.4f\n\n', CR_B);
% 检查CR_B 是否通过一致性检验
if CR_B >= 0.1
warning('准则层判断矩阵未能通过一致性检验，请重新调整专家打分。');
end
